const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];
return [{ json: { date: dateStr } }];

const date = $('Date Setup').first().json.date;

const metaData = $('Meta API').first().json.data || [];
const meta = metaData.length > 0 ? metaData[0] : {};
const spend = parseFloat(meta.spend || 0);
const impressions = parseInt(meta.impressions || 0);
const reach = parseInt(meta.reach || 0);
const clicks = parseInt(meta.clicks || 0);
const cpc = parseFloat(meta.cpc || 0);
const ctr = parseFloat(meta.ctr || 0);

const ga4Response = $('GA4 API').first().json;
const rows = ga4Response.rows || [];
let sesiones = 0, cta_clicks = 0, modal_opens = 0, form_submits = 0;
let bounceRate = 0;
rows.forEach(row => {
  const eventName = row.dimensionValues[0].value;
  const eventCount = parseInt(row.metricValues[2].value || 0);
  const sessions = parseInt(row.metricValues[0].value || 0);
  const br = parseFloat(row.metricValues[1].value || 0);
  if (eventName === 'session_start') { sesiones = sessions; bounceRate = br; }
  if (eventName === 'cta_click') cta_clicks = eventCount;
  if (eventName === 'form_modal_open') modal_opens = eventCount;
  if (eventName === 'form_submit') form_submits = eventCount;
});

const bitrix = $('Bitrix API').first().json.result || [];
const leads = bitrix.length;
let aprobados = 0, no_aprobados = 0;
bitrix.forEach(deal => {
  if (deal.STAGE_ID === 'C5:UC_SBLKBK') aprobados++;
  else if (deal.STAGE_ID === 'C5:UC_GFZ3OE') no_aprobados++;
});

const cpl = leads > 0 ? Math.round((spend / leads) * 100) / 100 : 0;
const cpl_aprobado = aprobados > 0 ? Math.round((spend / aprobados) * 100) / 100 : 0;
const tasa_conversion = sesiones > 0 ? Math.round((leads / sesiones) * 10000) / 100 : 0;
const tasa_modal_lead = modal_opens > 0 ? Math.round((form_submits / modal_opens) * 10000) / 100 : 0;
const tasa_cta_modal = cta_clicks > 0 ? Math.round((modal_opens / cta_clicks) * 10000) / 100 : 0;

return [{ json: {
  fecha: date, spend, impressions, reach, clicks,
  ctr: Math.round(ctr * 1000) / 1000,
  cpc: Math.round(cpc * 100) / 100,
  sesiones, cta_clicks, modal_opens, form_submits,
  leads, aprobados, no_aprobados, cpl, cpl_aprobado,
  bounce_rate: Math.round(bounceRate * 1000) / 1000,
  dispositivo_top: 'mobile',
  tasa_conversion_landing: tasa_conversion,
  tasa_modal_lead, tasa_cta_modal
}}];

const d = $('Consolidate Data').first().json;
const f = d.fecha;
const n = (v) => typeof v === 'number' ? v.toLocaleString('es-PE') : '0';
const m = (v) => 'S/' + (typeof v === 'number' ? v.toFixed(2) : '0.00');
const p = (v) => (typeof v === 'number' ? v : 0) + '%';

// Tasas del embudo
const tasa_click_ad = d.impressions > 0 ? ((d.clicks / d.impressions) * 100).toFixed(2) : '0';
const tasa_landing = d.clicks > 0 ? ((d.sesiones / d.clicks) * 100).toFixed(1) : '0';
const tasa_cta = d.sesiones > 0 ? ((d.cta_clicks / d.sesiones) * 100).toFixed(1) : '0';
const tasa_modal = d.cta_clicks > 0 ? ((d.modal_opens / d.cta_clicks) * 100).toFixed(1) : '0';
const tasa_form = d.modal_opens > 0 ? ((d.form_submits / d.modal_opens) * 100).toFixed(1) : '0';
const tasa_total = d.sesiones > 0 ? ((d.leads / d.sesiones) * 100).toFixed(2) : '0';

const c = '#1a237e';
const row = (label, value, rate, bg) => `<tr style="background:${bg || '#fff'};"><td style="padding:8px 12px;border-bottom:1px solid #e0e0e0;">${label}</td><td style="padding:8px 12px;border-bottom:1px solid #e0e0e0;text-align:right;font-weight:700;">${value}</td><td style="padding:8px 12px;border-bottom:1px solid #e0e0e0;text-align:right;color:#666;">${rate}</td></tr>`;

const html = `<div style="font-family:Arial,sans-serif;max-width:540px;margin:0 auto;">
<div style="background:${c};color:#fff;padding:16px 20px;border-radius:8px 8px 0 0;">
  <h2 style="margin:0;font-size:17px;">Reporte Diario - Landing Proper</h2>
  <p style="margin:4px 0 0;opacity:.7;font-size:12px;">${f}</p>
</div>
<div style="background:#fff;padding:0;border:1px solid #ddd;">

<table style="width:100%;border-collapse:collapse;">
<tr style="background:${c};color:#fff;"><td style="padding:8px 12px;font-weight:700;font-size:12px;">EMBUDO DE CONVERSION</td><td style="padding:8px 12px;text-align:right;font-size:12px;font-weight:700;">Cantidad</td><td style="padding:8px 12px;text-align:right;font-size:12px;font-weight:700;">Tasa</td></tr>
${row('1. Impresiones del anuncio', n(d.impressions), '-', '#f5f5f5')}
${row('2. Clicks en anuncio', n(d.clicks), tasa_click_ad + '% CTR')}
${row('3. Sesiones en landing', n(d.sesiones), tasa_landing + '% llegan', '#f5f5f5')}
${row('4. Clicks en CTA', n(d.cta_clicks), tasa_cta + '% interactuan')}
${row('5. Abren formulario', n(d.modal_opens), tasa_modal + '% abren modal', '#f5f5f5')}
${row('6. Envian formulario', n(d.form_submits), tasa_form + '% completan')}
<tr style="background:#e8f5e9;"><td style="padding:10px 12px;font-weight:800;font-size:14px;border-bottom:2px solid #1b5e20;">7. LEADS EN CRM</td><td style="padding:10px 12px;text-align:right;font-weight:800;font-size:20px;color:${c};border-bottom:2px solid #1b5e20;">${d.leads}</td><td style="padding:10px 12px;text-align:right;font-weight:700;color:#1b5e20;border-bottom:2px solid #1b5e20;">${tasa_total}% total</td></tr>
</table>

<table style="width:100%;border-collapse:collapse;">
<tr style="background:#e65100;color:#fff;"><td colspan="4" style="padding:8px 12px;font-weight:700;font-size:12px;">COSTOS E INVERSION DEL DIA</td></tr>
<tr>
  <td style="padding:10px;text-align:center;border-right:1px solid #eee;width:25%;"><div style="font-size:11px;color:#666;">Invertido</div><div style="font-size:18px;font-weight:800;color:#e65100;">${m(d.spend)}</div></td>
  <td style="padding:10px;text-align:center;border-right:1px solid #eee;width:25%;"><div style="font-size:11px;color:#666;">CPL</div><div style="font-size:18px;font-weight:800;color:${c};">${m(d.cpl)}</div></td>
  <td style="padding:10px;text-align:center;border-right:1px solid #eee;width:25%;"><div style="font-size:11px;color:#666;">CPL Aprob.</div><div style="font-size:18px;font-weight:800;color:#c62828;">${m(d.cpl_aprobado)}</div></td>
  <td style="padding:10px;text-align:center;width:25%;"><div style="font-size:11px;color:#666;">CPC</div><div style="font-size:18px;font-weight:800;">${m(d.cpc)}</div></td>
</tr>
<tr style="background:#f5f5f5;">
  <td colspan="2" style="padding:8px 12px;text-align:center;"><span style="color:#27ae60;font-weight:700;font-size:14px;">${d.aprobados} aprobados</span></td>
  <td colspan="2" style="padding:8px 12px;text-align:center;"><span style="color:#e74c3c;font-weight:700;font-size:14px;">${d.no_aprobados} no aprobados</span></td>
</tr>
</table>

<table style="width:100%;border-collapse:collapse;">
<tr style="background:#37474f;color:#fff;"><td colspan="4" style="padding:8px 12px;font-weight:700;font-size:12px;">ACUMULADO (${d.acc_dias} dias)</td></tr>
<tr>
  <td style="padding:8px;text-align:center;border-right:1px solid #eee;width:25%;"><div style="font-size:10px;color:#666;">Total invertido</div><div style="font-weight:700;color:#e65100;">${m(d.acc_spend)}</div></td>
  <td style="padding:8px;text-align:center;border-right:1px solid #eee;width:25%;"><div style="font-size:10px;color:#666;">Total leads</div><div style="font-weight:700;color:${c};">${n(d.acc_leads)}</div></td>
  <td style="padding:8px;text-align:center;border-right:1px solid #eee;width:25%;"><div style="font-size:10px;color:#666;">CPL prom.</div><div style="font-weight:700;">${m(d.acc_cpl)}</div></td>
  <td style="padding:8px;text-align:center;width:25%;"><div style="font-size:10px;color:#666;">Sesiones</div><div style="font-weight:700;">${n(d.acc_sesiones)}</div></td>
</tr>
</table>

</div>
<div style="background:#eceff1;padding:8px 20px;border-radius:0 0 8px 8px;text-align:center;border:1px solid #ddd;border-top:none;">
  <p style="margin:0;color:#90a4ae;font-size:10px;">landing-meta.proper.com.pe | Reporte automatico</p>
</div>
</div>`;

return [{ json: { ...d, emailHtml: html } }];

const date = $('Date Setup').first().json.date;

// ===== META ADS (solo campana landing) =====
const metaData = $('Meta API').first().json.data || [];
const meta = metaData.length > 0 ? metaData[0] : {};
const spend = parseFloat(meta.spend || 0);
const impressions = parseInt(meta.impressions || 0);
const reach = parseInt(meta.reach || 0);
const clicks = parseInt(meta.clicks || 0);
const cpc = parseFloat(meta.cpc || 0);
const ctr = parseFloat(meta.ctr || 0);

// ===== GA4 =====
const ga4Response = $('GA4 API').first().json;
const rows = ga4Response.rows || [];
let sesiones = 0, cta_clicks = 0, modal_opens = 0, form_submits = 0, bounceRate = 0;
rows.forEach(row => {
  const ev = row.dimensionValues[0].value;
  const cnt = parseInt(row.metricValues[2].value || 0);
  const sess = parseInt(row.metricValues[0].value || 0);
  const br = parseFloat(row.metricValues[1].value || 0);
  if (ev === 'session_start') { sesiones = sess; bounceRate = br; }
  if (ev === 'cta_click') cta_clicks = cnt;
  if (ev === 'form_modal_open') modal_opens = cnt;
  if (ev === 'form_submit') form_submits = cnt;
});

// ===== BITRIX =====
const bitrix = $('Bitrix API').first().json.result || [];
const leads = bitrix.length;
let aprobados = 0, no_aprobados = 0;
bitrix.forEach(d => {
  if (d.STAGE_ID === 'C5:UC_SBLKBK') aprobados++;
  else if (d.STAGE_ID === 'C5:UC_GFZ3OE') no_aprobados++;
});

// ===== ACUMULADO =====
const acc = $('Get Accumulated Totals').first().json;
const acc_spend = parseFloat(acc.total_spend || 0) + spend;
const acc_leads = parseInt(acc.total_leads || 0) + leads;
const acc_aprobados = parseInt(acc.total_aprobados || 0) + aprobados;
const acc_clicks = parseInt(acc.total_clicks || 0) + clicks;
const acc_sesiones = parseInt(acc.total_sesiones || 0) + sesiones;
const acc_dias = parseInt(acc.dias_activos || 0) + 1;

// ===== KPIs =====
const cpl = leads > 0 ? Math.round((spend / leads) * 100) / 100 : 0;
const cpl_aprobado = aprobados > 0 ? Math.round((spend / aprobados) * 100) / 100 : 0;
const tasa_conv = sesiones > 0 ? Math.round((leads / sesiones) * 10000) / 100 : 0;
const tasa_ml = modal_opens > 0 ? Math.round((form_submits / modal_opens) * 10000) / 100 : 0;
const tasa_cm = cta_clicks > 0 ? Math.round((modal_opens / cta_clicks) * 10000) / 100 : 0;
const acc_cpl = acc_leads > 0 ? Math.round((acc_spend / acc_leads) * 100) / 100 : 0;
const acc_cpl_aprob = acc_aprobados > 0 ? Math.round((acc_spend / acc_aprobados) * 100) / 100 : 0;

return [{ json: {
  fecha: date, spend, impressions, reach, clicks,
  ctr: Math.round(ctr * 1000) / 1000,
  cpc: Math.round(cpc * 100) / 100,
  sesiones, cta_clicks, modal_opens, form_submits,
  leads, aprobados, no_aprobados, cpl, cpl_aprobado,
  bounce_rate: Math.round(bounceRate * 1000) / 1000,
  dispositivo_top: 'mobile',
  tasa_conversion_landing: tasa_conv, tasa_modal_lead: tasa_ml, tasa_cta_modal: tasa_cm,
  acc_spend, acc_leads, acc_aprobados, acc_clicks, acc_sesiones, acc_dias, acc_cpl, acc_cpl_aprob
}}];

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];
return [{ json: { date: dateStr } }];
